                        'created_at' => '2026-03-18 08:57:07',
                        'updated_at' => '2026-03-18 10:01:31',
                        'deleted_at' => null,
                    ],
        ];

        // Break payload into manageable memory chunks and insert
        $chunks = array_chunk($payload, 200);
        foreach ($chunks as $chunk) {
            DB::table('tbl_pr')->insertOrIgnore($chunk);
        }

        Schema::enableForeignKeyConstraints();
    }
}
